    routeSlug: "100-same-tree",
    summary: "Given two binary trees, determine whether they are structurally identical and have the same node values at every corresponding position.",
    approach: "- Recursively compare both trees in a single DFS pass using the natural base cases: two null pointers are equal; one null and one non-null are not.\n- At each node, check that the current values match, then require both the left subtrees and the right subtrees to also be identical.\n- This works because tree equality is fully decomposable — a tree equals another if and only if the roots match and every subtree pair matches.\n- Short-circuit evaluation (`&&`) ensures we stop as soon as any mismatch is found.",
    code: "#include <cstddef>\nusing namespace std;\n\n// Definition for a binary tree node.\nstruct TreeNode {\n    int val;\n    TreeNode *left;\n    TreeNode *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n};\n\nclass Solution {\npublic:\n    bool isSameTree(TreeNode* p, TreeNode* q) {\n        // Both null: structurally identical at this position.\n        if (!p && !q) return true;\n        // Exactly one null: structures diverge.\n        if (!p || !q) return false;\n        // Values must match, then recurse on both subtrees.\n        return p->val == q->val\n            && isSameTree(p->left,  q->left)\n            && isSameTree(p->right, q->right);\n    }\n};\n",
    timeComplexity: "O(n)",
    spaceComplexity: "O(h), where h is the height of the tree (O(log n) balanced, O(n) worst-case skewed)",
