    code: "#include <vector>\n#include <unordered_map>\nusing namespace std;\n\n// Definition for a binary tree node.\nstruct TreeNode {\n    int val;\n    TreeNode *left, *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *l, TreeNode *r) : val(x), left(l), right(r) {}\n};\n\nclass Solution {\n    // Maps each value to its index in the inorder array for O(1) lookup.\n    unordered_map<int, int> inorderIdx;\n\n    // preStart/preEnd: current window in preorder\n    // inStart/inEnd:   current window in inorder\n    TreeNode* build(const vector<int>& preorder, int preStart, int preEnd,\n                    int inStart, int inEnd) {\n        if (preStart > preEnd) return nullptr;\n\n        int rootVal = preorder[preStart];\n        int mid     = inorderIdx[rootVal]; // root's position in inorder\n        int leftSize = mid - inStart;      // number of nodes in left subtree\n\n        TreeNode* root = new TreeNode(rootVal);\n        root->left  = build(preorder,\n                            preStart + 1, preStart + leftSize,\n                            inStart,      mid - 1);\n        root->right = build(preorder,\n                            preStart + leftSize + 1, preEnd,\n                            mid + 1,      inEnd);\n        return root;\n    }\n\npublic:\n    TreeNode* buildTree(vector<int>& preorder, vector<int>& inorder) {\n        int n = (int)preorder.size();\n        for (int i = 0; i < n; ++i)\n            inorderIdx[inorder[i]] = i;\n\n        return build(preorder, 0, n - 1, 0, n - 1);\n    }\n};",
