    code: "#include <functional>\n#include <mutex>\n#include <condition_variable>\nusing namespace std;\n\nclass Foo {\nprivate:\n    mutex mtx;\n    condition_variable cv;\n    int state = 1; // 1 → first ready, 2 → second ready, 3 → third ready\n\npublic:\n    Foo() {}\n\n    void first(function<void()> printFirst) {\n        unique_lock<mutex> lock(mtx);\n        // No waiting: first is always allowed to run immediately.\n        printFirst();\n        state = 2;\n        cv.notify_all();\n    }\n\n    void second(function<void()> printSecond) {\n        unique_lock<mutex> lock(mtx);\n        // Block until first() has completed.\n        cv.wait(lock, [this] { return state == 2; });\n        printSecond();\n        state = 3;\n        cv.notify_all();\n    }\n\n    void third(function<void()> printThird) {\n        unique_lock<mutex> lock(mtx);\n        // Block until second() has completed.\n        cv.wait(lock, [this] { return state == 3; });\n        printThird();\n    }\n};",
