    code: "#include <vector>\n#include <string>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<string> removeSubfolders(vector<string>& folder) {\n        // Lexicographic sort guarantees a parent always precedes its children.\n        sort(folder.begin(), folder.end());\n\n        vector<string> result;\n        for (const string& path : folder) {\n            // Check whether 'path' is a sub-folder of the last accepted root.\n            // Appending '/' prevents \"/ab\" from being treated as a child of \"/a\".\n            if (result.empty() || path.compare(0, result.back().size() + 1,\n                                                result.back() + '/') != 0) {\n                result.push_back(path);\n            }\n        }\n        return result;\n    }\n};\n",
