    code: "#include <string>\n#include <vector>\n#include <unordered_set>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    bool wordBreak(string s, vector<string>& wordDict) {\n        int n = s.size();\n        int maxLen = 0;\n        unordered_set<string> dict;\n        for (const string& w : wordDict) {\n            dict.insert(w);\n            maxLen = max(maxLen, (int)w.size());\n        }\n\n        // dp[i] == true  =>  s[0..i-1] can be segmented into dictionary words\n        vector<bool> dp(n + 1, false);\n        dp[0] = true;\n\n        for (int i = 1; i <= n; ++i) {\n            // Try every split point j where s[j..i-1] might be a word\n            for (int j = max(0, i - maxLen); j < i; ++j) {\n                if (dp[j] && dict.count(s.substr(j, i - j))) {\n                    dp[i] = true;\n                    break;\n                }\n            }\n        }\n\n        return dp[n];\n    }\n};\n",
