    code: "#include <algorithm>\n#include <climits>\nusing namespace std;\n\n// Definition for a binary tree node.\nstruct TreeNode {\n    int val;\n    TreeNode *left;\n    TreeNode *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n};\n\nclass Solution {\npublic:\n    int goodNodes(TreeNode* root) {\n        return dfs(root, INT_MIN);\n    }\n\nprivate:\n    // Returns the count of good nodes in the subtree rooted at `node`,\n    // given that `pathMax` is the maximum value on the path from the root to `node`'s parent.\n    int dfs(TreeNode* node, int pathMax) {\n        if (!node) return 0;\n\n        // A node is \"good\" if no ancestor has a strictly greater value.\n        int isGood = (node->val >= pathMax) ? 1 : 0;\n        int newMax  = max(pathMax, node->val);\n\n        return isGood\n             + dfs(node->left,  newMax)\n             + dfs(node->right, newMax);\n    }\n};\n",
