    approach: "- Model the problem as finding a **Minimum Spanning Tree (MST)** on a complete graph where edge weights are Manhattan distances between pairs of points.\n- Use **Prim's algorithm** with an O(n²) dense-graph formulation: maintain a `minDist` array tracking the cheapest known edge connecting each unvisited node to the current MST.\n- At each of n iterations, greedily pick the unvisited node with the smallest `minDist`, add its cost to the answer, mark it visited, then relax all remaining nodes against this newly added node.\n- This avoids explicitly enumerating all O(n²) edges upfront; the implicit edge weight is computed on-the-fly, keeping both time and space at O(n²) and O(n) respectively.",
    code: "#include <vector>\n#include <cmath>\n#include <climits>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    int minCostConnectPoints(vector<vector<int>>& points) {\n        int n = points.size();\n\n        // minDist[i] = cheapest edge connecting node i to the current MST\n        vector<int> minDist(n, INT_MAX);\n        vector<bool> inMST(n, false);\n\n        minDist[0] = 0;           // start growing MST from node 0\n        int totalCost = 0;\n\n        for (int iter = 0; iter < n; ++iter) {\n            // Pick the cheapest unvisited node\n            int u = -1;\n            for (int i = 0; i < n; ++i) {\n                if (!inMST[i] && (u == -1 || minDist[i] < minDist[u]))\n                    u = i;\n            }\n\n            inMST[u] = true;\n            totalCost += minDist[u];\n\n            // Relax neighbors: update their best known connection to the MST\n            for (int v = 0; v < n; ++v) {\n                if (!inMST[v]) {\n                    int dist = abs(points[v][0] - points[u][0])\n                             + abs(points[v][1] - points[u][1]);\n                    minDist[v] = min(minDist[v], dist);\n                }\n            }\n        }\n\n        return totalCost;\n    }\n};\n",
