    code: "#include <vector>\n#include <string>\nusing namespace std;\n\nclass Solution {\n    // Maps digit '2'-'9' to its phone keypad letters\n    const string kMap[8] = {\"abc\", \"def\", \"ghi\", \"jkl\", \"mno\", \"pqrs\", \"tuv\", \"wxyz\"};\n\n    void backtrack(const string& digits, int idx, string& path, vector<string>& result) {\n        if (idx == (int)digits.size()) {\n            result.push_back(path);\n            return;\n        }\n        for (char c : kMap[digits[idx] - '2']) {\n            path.push_back(c);\n            backtrack(digits, idx + 1, path, result);\n            path.pop_back();   // undo choice\n        }\n    }\n\npublic:\n    vector<string> letterCombinations(string digits) {\n        vector<string> result;\n        if (digits.empty()) return result;  // guard: no digits -> no combinations\n\n        string path;\n        backtrack(digits, 0, path, result);\n        return result;\n    }\n};",
