    code: "#include <string>\n#include <stack>\n#include <unordered_map>\nusing namespace std;\n\nclass Solution {\npublic:\n    bool isValid(string s) {\n        // Maps each opener to its expected closer\n        unordered_map<char, char> match = {\n            {'(', ')'},\n            {'{', '}'},\n            {'[', ']'}\n        };\n\n        stack<char> st;\n        for (char c : s) {\n            if (match.count(c)) {\n                // Push the expected closing bracket\n                st.push(match[c]);\n            } else {\n                // Closer must match the top of the stack\n                if (st.empty() || st.top() != c)\n                    return false;\n                st.pop();\n            }\n        }\n\n        // Valid only if all openers were matched\n        return st.empty();\n    }\n};",
