    routeSlug: "209-minimum-size-subarray-sum",
    summary: "Given a positive integer target and an array of positive integers, find the minimum length of a contiguous subarray whose sum is at least target, returning 0 if no such subarray exists.",
    approach: "- Use a sliding window with two pointers (`left` and `right`) that expand by advancing `right` and shrink by advancing `left`.\n- Whenever the current window sum meets or exceeds `target`, record the window length and then shrink from the left to find a potentially smaller valid window.\n- Because all values are positive, shrinking always decreases the sum, so each pointer moves forward at most n times — giving linear time overall.",
    code: "#include <vector>\n#include <climits>\nusing namespace std;\n\nclass Solution {\npublic:\n    int minSubArrayLen(int target, vector<int>& nums) {\n        int left = 0, windowSum = 0;\n        int minLen = INT_MAX;\n\n        for (int right = 0; right < (int)nums.size(); ++right) {\n            windowSum += nums[right];\n\n            // Shrink from the left as long as the window satisfies the condition.\n            while (windowSum >= target) {\n                minLen = min(minLen, right - left + 1);\n                windowSum -= nums[left++];\n            }\n        }\n\n        return minLen == INT_MAX ? 0 : minLen;\n    }\n};\n",
    timeComplexity: "O(n)",
    spaceComplexity: "O(1)",
