    summary: "Given an integer n, produce every possible string of n opening and n closing parentheses that forms a valid (properly nested) sequence.",
    approach: "- Use recursive backtracking, tracking how many `(` and `)` have been placed so far.\n- At each step, add `(` if the open count is still below n, and add `)` only when the close count is strictly less than the open count — this invariant guarantees validity at every prefix.\n- When the current string reaches length 2n, it is a complete valid combination and is recorded.\n- Because the constraint prunes invalid branches immediately, no post-generation filtering is needed; the number of valid results equals the n-th Catalan number.",
    code: "#include <string>\n#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<string> generateParenthesis(int n) {\n        vector<string> result;\n        dfs(result, \"\", 0, 0, n);\n        return result;\n    }\n\nprivate:\n    // open  = '(' placed so far\n    // close = ')' placed so far\n    void dfs(vector<string>& result, string cur, int open, int close, int n) {\n        if ((int)cur.size() == 2 * n) {\n            result.push_back(cur);\n            return;\n        }\n        // Can add '(' as long as we have quota remaining\n        if (open < n)\n            dfs(result, cur + '(', open + 1, close, n);\n        // Can add ')' only when it won't exceed open count (keeps prefix valid)\n        if (close < open)\n            dfs(result, cur + ')', open, close + 1, n);\n    }\n};\n",
