    routeSlug: "3-longest-substring-without-repeating-characters",
    summary: "Given a string, find the length of the longest contiguous substring in which no character appears more than once.",
    approach: "- Use a **sliding window** defined by two pointers (`left`, `right`) that always brackets a duplicate-free substring.\n- Keep a hash map from each character to its most-recently-seen index so we can jump the left boundary forward in O(1) instead of crawling one step at a time.\n- When `right` lands on a character already inside the window (its stored index >= `left`), advance `left` past that earlier occurrence, eliminating the duplicate instantly.\n- Update the answer after every step; total work is O(n) because each character is visited at most twice (once by each pointer).",
    code: "#include <string>\n#include <unordered_map>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    int lengthOfLongestSubstring(string s) {\n        unordered_map<char, int> lastSeen; // char -> most recent index\n        int best = 0;\n\n        // [left, right] is the current duplicate-free window\n        for (int left = 0, right = 0; right < (int)s.size(); ++right) {\n            char c = s[right];\n\n            // If c is inside the current window, shrink from the left\n            auto it = lastSeen.find(c);\n            if (it != lastSeen.end() && it->second >= left)\n                left = it->second + 1;\n\n            lastSeen[c] = right;\n            best = max(best, right - left + 1);\n        }\n\n        return best;\n    }\n};",
