    approach: "- Maintain a fixed-size window of length `s1.size()` sliding over s2, tracking character frequency differences in a 26-element array.\n- A counter `formed` starts at the number of distinct characters in s1; it decrements each time a character's count in the window exactly satisfies s1's requirement, and increments when it drops below.\n- When `formed == 0`, every character of s1 is fully matched inside the current window, so a permutation was found.\n- Shrinking the left edge mirrors the right-edge expansion, keeping window size fixed at `|s1|`.",
    code: "#include <string>\n#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    bool checkInclusion(string s1, string s2) {\n        if (s1.size() > s2.size()) return false;\n\n        // need[c] = how many more of character c we still need in the window\n        // positive  => still needed, negative => window has excess\n        vector<int> need(26, 0);\n        for (char c : s1) ++need[c - 'a'];\n\n        // formed = number of distinct characters still unsatisfied\n        int formed = 0;\n        for (int x : need) if (x > 0) ++formed;\n\n        int left = 0;\n        for (int right = 0; right < (int)s2.size(); ++right) {\n            // Expand right edge\n            int rc = s2[right] - 'a';\n            --need[rc];\n            if (need[rc] == 0) --formed;  // just satisfied this character\n\n            // Window reached target size: check, then shrink left edge\n            if (right - left + 1 == (int)s1.size()) {\n                if (formed == 0) return true;\n\n                int lc = s2[left] - 'a';\n                if (need[lc] == 0) ++formed;  // about to become unsatisfied\n                ++need[lc];\n                ++left;\n            }\n        }\n        return false;\n    }\n};\n",
