    code: "#include <vector>\n#include <algorithm>\n#include <array>\nusing namespace std;\n\nclass Solution {\npublic:\n    int leastInterval(vector<char>& tasks, int n) {\n        // Count frequency of each task label.\n        array<int, 26> freq{};\n        for (char c : tasks) ++freq[c - 'A'];\n\n        // Find the maximum frequency and how many tasks share it.\n        int f_max = *max_element(freq.begin(), freq.end());\n        int count_max = (int)count(freq.begin(), freq.end(), f_max);\n\n        // Minimum slots needed:\n        //   (f_max - 1) full \"frames\" of size (n + 1), plus a final partial\n        //   frame containing all tasks tied for the top frequency.\n        // If tasks are dense, no idles are needed — just use task count.\n        int min_slots = (f_max - 1) * (n + 1) + count_max;\n        return max((int)tasks.size(), min_slots);\n    }\n};\n",
