    approach: "- Use **Union-Find (Disjoint Set Union)** with path compression and union-by-rank.\n- Initialize each node as its own parent. Process edges in order; for each edge, find the roots of both endpoints.\n- If both endpoints share the same root, a cycle would be formed — this edge is redundant; return it immediately.\n- Otherwise, merge the two components by attaching the smaller-rank tree under the larger-rank root (union-by-rank), keeping the structure nearly flat.",
    code: "#include <vector>\nusing namespace std;\n\nclass Solution {\n    // Find root with path compression\n    int find(vector<int>& parent, int x) {\n        if (parent[x] != x)\n            parent[x] = find(parent, parent[x]); // path compression\n        return parent[x];\n    }\n\n    // Union by rank; returns false if x and y are already in the same set\n    bool unite(vector<int>& parent, vector<int>& rank, int x, int y) {\n        int rx = find(parent, x), ry = find(parent, y);\n        if (rx == ry) return false; // cycle detected\n        if (rank[rx] < rank[ry]) swap(rx, ry);\n        parent[ry] = rx;            // attach smaller tree under larger root\n        if (rank[rx] == rank[ry]) ++rank[rx];\n        return true;\n    }\n\npublic:\n    vector<int> findRedundantConnection(vector<vector<int>>& edges) {\n        int n = static_cast<int>(edges.size());\n        vector<int> parent(n + 1), rank(n + 1, 0);\n        for (int i = 1; i <= n; ++i) parent[i] = i; // each node is its own root\n\n        for (const auto& e : edges) {\n            if (!unite(parent, rank, e[0], e[1]))\n                return e; // this edge creates a cycle — it is redundant\n        }\n        return {}; // guaranteed not reached per problem constraints\n    }\n};",
