    code: "#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    void setZeroes(vector<vector<int>>& matrix) {\n        int m = matrix.size(), n = matrix[0].size();\n\n        // Does the first row itself contain a zero?\n        bool firstRowZero = false;\n        for (int j = 0; j < n; ++j)\n            if (matrix[0][j] == 0) { firstRowZero = true; break; }\n\n        // Use row 0 and col 0 as sentinels for the rest of the matrix.\n        // We skip row 0 (handled separately) and use matrix[i][0] for rows.\n        for (int i = 1; i < m; ++i)\n            for (int j = 0; j < n; ++j)\n                if (matrix[i][j] == 0) {\n                    matrix[i][0] = 0;   // mark row i\n                    matrix[0][j] = 0;   // mark col j\n                }\n\n        // Zero out cells guided by sentinels (skip first row/col for now).\n        for (int i = 1; i < m; ++i)\n            for (int j = 1; j < n; ++j)\n                if (matrix[i][0] == 0 || matrix[0][j] == 0)\n                    matrix[i][j] = 0;\n\n        // Zero out first column if any of rows 1..m-1 was a zero-row.\n        if (matrix[0][0] == 0)\n            for (int i = 1; i < m; ++i)\n                matrix[i][0] = 0;\n\n        // Zero out first row if it originally contained a zero.\n        if (firstRowZero)\n            for (int j = 0; j < n; ++j)\n                matrix[0][j] = 0;\n    }\n};\n",
