    routeSlug: "76-minimum-window-substring",
    summary: "Given two strings `s` and `t`, find the shortest contiguous substring of `s` that contains every character of `t` (with multiplicity), returning an empty string if no such window exists.",
    approach: "- Build a frequency table for characters in `t`, and track how many distinct characters still need to be fully satisfied (`need`).\n- Expand the right pointer character by character; when a character's count in the window satisfies its required frequency, decrement `need`.\n- Once `need == 0` (all characters satisfied), shrink the left pointer greedily: record the window if it is the smallest seen, then release the left character and, if that makes its count go below the required amount, increment `need` to exit the inner loop.\n- Because each character is added and removed at most once, the whole scan is linear.",
    code: "#include <string>\n#include <climits>\nusing namespace std;\n\nclass Solution {\npublic:\n    string minWindow(string s, string t) {\n        if (s.empty() || t.empty() || s.size() < t.size()) return \"\";\n\n        // freq[c] > 0  → still need more of c\n        // freq[c] <= 0 → window already satisfies c (possibly excess)\n        int freq[128] = {};\n        for (char c : t) ++freq[(unsigned char)c];\n\n        // count of distinct characters whose requirement is not yet met\n        int need = 0;\n        for (int f : freq) if (f > 0) ++need;\n\n        int left = 0, bestStart = -1, bestLen = INT_MAX;\n\n        for (int right = 0; right < (int)s.size(); ++right) {\n            // include s[right] in window\n            char rc = s[right];\n            --freq[(unsigned char)rc];\n            if (freq[(unsigned char)rc] == 0) --need; // this character is now exactly satisfied\n\n            // shrink from left while all requirements are met\n            while (need == 0) {\n                int windowLen = right - left + 1;\n                if (windowLen < bestLen) {\n                    bestLen  = windowLen;\n                    bestStart = left;\n                }\n\n                // release s[left]\n                char lc = s[left++];\n                if (++freq[(unsigned char)lc] > 0) ++need; // we just lost a required character\n            }\n        }\n\n        return bestStart == -1 ? \"\" : s.substr(bestStart, bestLen);\n    }\n};\n",
    timeComplexity: "O(n)",
    spaceComplexity: "O(1)",
