    summary: "Given an integer array that may contain duplicates, find all unique subsets (the power set) and return them without any duplicate subsets.",
    approach: "- Sort the input so duplicate values are adjacent, making it easy to detect and skip them.\n- Use backtracking: at each index, make a binary choice — include the current element (recurse to the next index) or skip it.\n- When skipping, advance past all consecutive copies of the current value so the same element is never used as the \"skip\" branch more than once at the same decision level.\n- This guarantees every unique subset is generated exactly once without a hash-set or post-filtering step.",
    code: "#include <vector>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\n    void backtrack(const vector<int>& nums, int idx, vector<int>& cur, vector<vector<int>>& res) {\n        if (idx == (int)nums.size()) {\n            res.push_back(cur);\n            return;\n        }\n\n        // Choice 1: include nums[idx]\n        cur.push_back(nums[idx]);\n        backtrack(nums, idx + 1, cur, res);\n        cur.pop_back();\n\n        // Choice 2: skip nums[idx] (and every duplicate of it at this level)\n        int next = idx + 1;\n        while (next < (int)nums.size() && nums[next] == nums[idx])\n            ++next;\n        backtrack(nums, next, cur, res);\n    }\n\npublic:\n    vector<vector<int>> subsetsWithDup(vector<int>& nums) {\n        sort(nums.begin(), nums.end());\n        vector<vector<int>> res;\n        vector<int> cur;\n        backtrack(nums, 0, cur, res);\n        return res;\n    }\n};\n",
    timeComplexity: "O(2^n * n)",
    spaceComplexity: "O(2^n * n)",
