    code: "#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<vector<int>> intervalIntersection(vector<vector<int>>& firstList,\n                                             vector<vector<int>>& secondList) {\n        vector<vector<int>> result;\n        int i = 0, j = 0;\n\n        while (i < (int)firstList.size() && j < (int)secondList.size()) {\n            // Overlap region, if any, is bounded by the later start and earlier end.\n            int lo = max(firstList[i][0], secondList[j][0]);\n            int hi = min(firstList[i][1], secondList[j][1]);\n\n            if (lo <= hi)\n                result.push_back({lo, hi});\n\n            // The interval that ends sooner is exhausted; move past it.\n            if (firstList[i][1] < secondList[j][1])\n                ++i;\n            else\n                ++j;\n        }\n\n        return result;\n    }\n};",
